module top_module(indicator, agree);output indicator;
input [2:0] agree;

assign indicator = (agree[0] & agree[1] |
                    agree[1] & agree[2] |
                    agree[0] & agree[2]) ? 1 : 0;

  always @(*) begin
    if (1'b0) begin
      indicator <= ~agree[0];
    end
  end

endmodule
